// Filter, Insert & Screen Grants (All Orgs, Internal Loop)
// ============================================================
// Scheduled version: processes grants for ALL organizations.
// Replaces Check Already Tracked, Code in JavaScript5, AI filter,
// Build Location Payload, insert, and eligibility screener nodes.
// Loops internally in JS to avoid n8n loop node data shape bugs.
// ============================================================

const BATCH_SIZE = 30;
const DEDUP_BATCH = 500;
const items = $input.all();

const openAiKey = 'YOUR_OPENAI_API_KEY_HERE';

const supabaseUrl = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZndWRobGNrdHNzdHdweHd0d3p6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDk2NjA5NSwiZXhwIjoyMDg2NTQyMDk1fQ.lDXOCM7CStNfF0G-ZENg5x1dyQ0ytXHGtJ8DjQNd03I';
const supaHeaders = {
  'apikey': supabaseKey,
  'Authorization': 'Bearer ' + supabaseKey,
  'Content-Type': 'application/json',
};
const supaReadHeaders = {
  'apikey': supabaseKey,
  'Authorization': 'Bearer ' + supabaseKey,
};

// --- STEP 1: Fetch ALL organizations ---
const orgs = await this.helpers.httpRequest({
  method: 'GET',
  url: supabaseUrl + '/organizations?select=id,geographic_focus,address&plan=neq.free',
  headers: supaReadHeaders,
});

if (!Array.isArray(orgs) || orgs.length === 0) {
  return [{ json: { error: true, message: 'No organizations found' } }];
}

// --- STEP 2: Fetch narratives for all orgs ---
const orgNarratives = {};
for (const org of orgs) {
  try {
    const narratives = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/documents?org_id=eq.' + encodeURIComponent(org.id) + '&select=title,extracted_text,category&order=updated_at.desc&limit=10',
      headers: supaReadHeaders,
    });
    if (Array.isArray(narratives) && narratives.length > 0) {
      orgNarratives[org.id] = narratives.map(n => (n.title || n.category || '') + ': ' + (n.extracted_text || '')).join('\n\n');
    } else {
      orgNarratives[org.id] = '';
    }
  } catch (e) {
    orgNarratives[org.id] = '';
  }
}

// --- STEP 3: Build all grants list ---
const allGrants = [];
for (const item of items) {
  const grant = item.json.grant || item.json;
  const oppNum = (grant.oppNum || grant.source_id || '').trim();
  if (!oppNum) continue;
  allGrants.push({
    title: grant.title || '',
    agency: grant.agency || null,
    agencyCode: grant.agencyCode || '',
    description: grant.description || '',
    awardFloor: grant.awardFloor || 0,
    awardCeiling: grant.awardCeiling || 0,
    openDate: grant.openDate || '',
    closeDate: grant.closeDate || '',
    status: grant.status || '',
    source: grant.source || 'Grant Scanner',
    source_id: oppNum,
    source_url: grant.link || grant.source_url,
  });
}

if (allGrants.length === 0) {
  return [{ json: { message: 'No grants to process' } }];
}

// --- STEP 4: Batch dedup — fetch all existing source_id+org_id pairs ---
const uniqueSourceIds = [...new Set(allGrants.map(g => g.source_id))];
const existingPairs = new Set();

for (let i = 0; i < uniqueSourceIds.length; i += DEDUP_BATCH) {
  const chunk = uniqueSourceIds.slice(i, i + DEDUP_BATCH);
  const filter = chunk.map(id => '"' + id.replace(/"/g, '') + '"').join(',');
  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/grants?source_id=in.(' + filter + ')&select=source_id,org_id',
      headers: supaReadHeaders,
    });
    if (Array.isArray(response)) {
      for (const r of response) {
        existingPairs.add(r.org_id + '::' + r.source_id);
      }
    }
  } catch(e) {}
}

// --- STEP 5: Process each org ---
let totalInserted = 0;
let totalScreened = 0;

const systemPrompt = `You are a grant eligibility and classification assistant. Given a grant, an organization with its location, and the organization's narratives (which describe its mission, programs, and focus areas), first classify the grant type, then determine if the organization is eligible by location, then evaluate niche alignment.

STEP 1 - CLASSIFY THE GRANT TYPE:
- Federal: Funded by federal agencies (HHS, SAMHSA, ACF, DOL, ED, HUD, USDA, etc.) or listed on Grants.gov. grant_state = null.
 - State grants: The organization is ONLY eligible if it operates in, is headquartered in, or serves communities in the grant's state.
    1. Identify the grant's state by reading the full grant details.
    2. Check the organization's geographic_focus and address fields.
    3. The org is eligible if ANY match the grant's state.
    4. Matching rules: Accept abbreviations, typos, partial matches.
    5. The org is NOT eligible if its location clearly indicates a different state.
    6. If no location data, mark eligible.
- Philanthropic: From private foundations, trusts, corporate giving. grant_state = null.

STEP 2 - DETERMINE LOCATION ELIGIBILITY:
- Federal/Philanthropic: Always eligible.
- State: Only eligible if org is in or serves that state.

STEP 3 - EVALUATE NICHE ALIGNMENT:
- Match if grant's focus overlaps with org's mission/programs.
- Be GENEROUS — only reject obvious mismatches.
- If no narratives, default niche_aligned = true.

The grant must pass BOTH location AND niche to be eligible.

Return ONLY valid JSON — an array with one object per grant:
{
  "grant_type": "federal" or "state" or "philanthropic",
  "grant_state": "Full state name if state grant, otherwise null",
  "location_eligible": true or false,
  "niche_aligned": true or false,
  "eligible": true or false,
  "reason": "brief explanation"
}`;

for (const org of orgs) {
  // Filter grants not yet tracked for this org
  const newGrants = allGrants.filter(g => !existingPairs.has(org.id + '::' + g.source_id));

  if (newGrants.length === 0) continue;

  const nicheSummary = orgNarratives[org.id] || '';

  // Process in AI batches
  const totalBatches = Math.ceil(newGrants.length / BATCH_SIZE);

  for (let b = 0; b < totalBatches; b++) {
    const start = b * BATCH_SIZE;
    const batch = newGrants.slice(start, start + BATCH_SIZE);

    // Build AI prompt
    const userPrompt = `
    Organization:
    - ID: ${org.id}
    - Location: ${org.geographic_focus ? (Array.isArray(org.geographic_focus) ? org.geographic_focus.join(', ') : org.geographic_focus) : 'Not set'}
    - Address: ${org.address || 'Not set'}

    Organization Narratives:
    ${nicheSummary || 'No narratives available'}

    Grants:
    ${JSON.stringify(batch, null, 2)}`;

    let parsedResults = [];
    try {
      const aiResponse = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.openai.com/v1/chat/completions',
        headers: {
          'Authorization': 'Bearer ' + openAiKey,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          model: 'gpt-4.1-mini',
          messages: [
            { role: 'system', content: systemPrompt },
            { role: 'user', content: userPrompt }
          ],
          temperature: 0,
        }),
      });

      const aiText = aiResponse.choices?.[0]?.message?.content || '[]';
      const cleaned = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
      const parsed = JSON.parse(cleaned);
      parsedResults = Array.isArray(parsed) ? parsed : [parsed];
    } catch(e) {
      parsedResults = batch.map(() => ({
        grant_type: 'federal', grant_state: null,
        location_eligible: true, niche_aligned: true,
        eligible: true, reason: 'AI parse failed, defaulting to eligible'
      }));
    }

    // Build insert payloads
    const toInsert = [];
    batch.forEach((grant, index) => {
      const parsed = parsedResults[index] || parsedResults[0] || {
        grant_type: 'federal', grant_state: null,
        location_eligible: true, niche_aligned: true,
        eligible: true, reason: 'No AI result'
      };

      if (parsed.eligible === false) return;

      const description = grant.description || '';
      const descriptionHtml = '<div><h3>Grant Opportunity</h3>' +
        '<p><strong>Source:</strong> ' + (grant.source || '') + '</p>' +
        '<p><strong>Agency:</strong> ' + (grant.agency || '') + '</p>' +
        '<p><strong>Type:</strong> ' + (parsed.grant_type || 'unknown') + '</p>' +
        (parsed.grant_state ? '<p><strong>State:</strong> ' + parsed.grant_state + '</p>' : '') +
        '<p><strong>Award Range:</strong> $' + (grant.awardFloor || 0) + ' - $' + (grant.awardCeiling || 0) + '</p>' +
        '<p><strong>Open Date:</strong> ' + (grant.openDate || '') + '</p>' +
        '<p><strong>Deadline:</strong> ' + (grant.closeDate || '') + '</p>' +
        '<hr><h4>Description:</h4>' +
        '<p>' + description + '</p>' +
        '<p><em>Location Filter: ' + (parsed.reason || 'N/A') + '</em></p>' +
        '<hr>' +
        '<p><a href="' + (grant.source_url || '') + '">View Original Listing</a></p>' +
        '</div>';

      let deadlineValue = null;
      if (grant.closeDate && grant.closeDate !== 'See listing' && grant.closeDate !== 'Not specified' && grant.closeDate !== 'Rolling') {
        const d = new Date(grant.closeDate);
        if (!isNaN(d.getTime())) {
          const yyyy = d.getUTCFullYear();
          const mm = String(d.getUTCMonth() + 1).padStart(2, '0');
          const dd = String(d.getUTCDate()).padStart(2, '0');
          deadlineValue = yyyy + '-' + mm + '-' + dd + 'T00:00:00.000Z';
        } else {
          deadlineValue = grant.closeDate;
        }
      }

      toInsert.push({
        org_id: org.id,
        title: grant.title || '',
        funder_name: grant.agency || null,
        description: description,
        amount: grant.awardCeiling > 0 ? grant.awardCeiling : null,
        deadline: deadlineValue,
        stage: 'discovery',
        source: grant.source || 'Grant Scanner',
        source_id: grant.source_id,
        source_url: grant.source_url,
        metadata: {
          agency_code: grant.agencyCode,
          open_date: grant.openDate,
          award_floor: grant.awardFloor,
          award_ceiling: grant.awardCeiling,
          grant_type: parsed.grant_type || 'unknown',
          grant_state: parsed.grant_state || null,
          location_filter_reason: parsed.reason || '',
          location_eligible: parsed.location_eligible !== false,
          niche_aligned: parsed.niche_aligned !== false,
          priority: 'medium',
          description_html: descriptionHtml
        }
      });
    });

    // Insert eligible grants
    if (toInsert.length > 0) {
      for (const grant of toInsert) {
        try {
          await this.helpers.httpRequest({
            method: 'POST',
            url: supabaseUrl + '/grants?on_conflict=org_id,source_id',
            headers: { ...supaHeaders, 'Prefer': 'return=representation,resolution=ignore-duplicates' },
            body: JSON.stringify(grant),
          });
          totalInserted++;
          // Add to existingPairs so we don't duplicate for next org
          existingPairs.add(grant.org_id + '::' + grant.source_id);
        } catch(e) {}
      }
    }

    // Call eligibility screener
    for (const grant of toInsert) {
      try {
        await this.helpers.httpRequest({
          method: 'POST',
          url: 'https://n8n.thebrownmine.com/webhook/screen-grant',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            url: grant.source_url || '',
            grantid: '',
            orgId: grant.org_id || '',
            grantData: {
              title: grant.title || '',
              agency: grant.funder_name || '',
              awardRange: grant.amount ? String(grant.amount) : 'Not specified',
              deadline: grant.deadline || '',
              description: grant.description || '',
              source: grant.source || '',
              org_id: grant.org_id || ''
            }
          }),
          timeout: 60000,
        });
        totalScreened++;
      } catch(e) {}
    }
  }
}

return [{ json: { success: true, totalInserted, totalScreened, totalGrants: allGrants.length, orgsProcessed: orgs.length } }];
